    name = data['name']
    email = data['email']
    interests = data['interests']
    format = data['format']

    print(f"New subscription: {name} <{email}> interested in {interests} as {format}.")

    return jsonify(success=True)

@app.route('/')
def home():
    return render_template('home.html')

